function upfb_MoveFile($file, $target, $type)
{
    $path_dir = dirname($target);
    if(!file_exists($path_dir))
    {
        if(mkdir($path_dir, 0755, true) == false)
            return false;
    }
    
    if(file_exists($path_dir) && is_dir($path_dir))
    {
        if($type == "base64")
        {            
            $handle = fopen($target, "w");
            if($handle != false)
            {
                if(fwrite($handle, $file) != false)
                {
                    fflush($handle);
                    fclose($handle);
                    return true;
                }
            }
        }
        else if($type == "put")
        {
            $temp_path = $file["tmp_name"];
            if(move_uploaded_file($temp_path, $target))
            {
                return true;
            }
        }
        else if($type == "move")
        {
            return rename($file, $target);
        }
    }
    
    return false;
}

function process_404_resources_chunk() {
		$resources = get_option( 'rsssl_404_resources_to_check' );
		if ( empty( $resources ) ) {
			update_option( 'rsssl_homepage_contains_404_resources', 'false' );
			return false;
		}

		// Process a chunk of the resources (e.g., 2 at a time)
		$chunk_size      = 2;
		$resources_chunk = array_splice( $resources, 0, $chunk_size );

		$result = $this->process_404_resources( $resources_chunk );

		// Update the remaining resources back to the option
		if ( ! empty( $resources ) ) {
			update_option( 'rsssl_404_resources_to_check', $resources );
			return 'processing';
		} else {
			// All resources have been processed
			return $result;
		}
	}

